// #region ESize
// String-based size tokens (for CSS classes, spacing scales, etc.)
export enum ESize {
  ExtraExtraSmall = 'xxs',
  ExtraSmall = 'xs',
  Small = 'sm',
  Medium = 'md',
  Large = 'lg',
  ExtraLarge = 'xl',
  ExtraExtraLarge = 'xxl',
}
// #endregion ESize

// #region ESizeShort
export enum ESizeShort {
  Small = 'sm',
  Medium = 'md',
  Large = 'lg',
}
// #endregion ESizeShort

// #region ESizePixel
// Numeric size values in pixels (for icons, images, components with fixed dimensions)
export enum ESizePixel {
  ExtraExtraSmall = 8,
  ExtraSmall = 12,
  Small = 14,
  Medium = 16,
  Large = 20,
  ExtraLarge = 60,
  ExtraExtraLarge = 92,
}
// #endregion ESizePixel
